solution_code:
#include <iostream>

class Hero {
private:
    int m_hp{ 0 };
    int m_maxHp{ 0 };

public:
    Hero(int maxHp) : m_hp{ maxHp }, m_maxHp{ maxHp } {}

    int getHp() const { return m_hp; }

    void applyDamage(int d) {
        m_hp -= d;
        if (m_hp < 0)      m_hp = 0;
        if (m_hp > m_maxHp) m_hp = m_maxHp;
    }

    void applyHeal(int h) {
        m_hp += h;
        if (m_hp < 0)      m_hp = 0;
        if (m_hp > m_maxHp) m_hp = m_maxHp;
    }
};

int main() {
    int maxHp, damage, heal;
    std::cin >> maxHp >> damage >> heal;

    Hero hero{ maxHp };
    hero.applyDamage(damage);
    std::cout << "HP after damage: " << hero.getHp() << '\n';
    hero.applyHeal(heal);
    std::cout << "HP after heal: " << hero.getHp() << '\n';

    return 0;
}

