#include <iostream>

class SafeCounter {
private:
    int m_count{ 0 };

public:
    void add(int n) {
        // Bug: wrong comparison lets negatives through
        if (n >= 0)
            m_count += n;
    }

    int getCount() const { return m_count; }
};

int main() {
    int a, b;
    std::cin >> a >> b;

    SafeCounter sc;
    sc.add(a);
    sc.add(b);

    std::cout << "Count: " << sc.getCount() << '\n';
    return 0;
}

solution_code:
#include <iostream>

class SafeCounter {
private:
    int m_count{ 0 };

public:
    void add(int n) {
        if (n > 0)
            m_count += n;
    }

    int getCount() const { return m_count; }
};

int main() {
    int a, b;
    std::cin >> a >> b;

    SafeCounter sc;
    sc.add(a);
    sc.add(b);

    std::cout << "Count: " << sc.getCount() << '\n';
    return 0;
}
